const totalPagesInput = document.getElementById("total-pages");
const setupBtn = document.getElementById("setup-btn");
const drawBtn = document.getElementById("draw-btn");
const resetBtn = document.getElementById("reset-btn");
const messageEl = document.getElementById("message");
const currentPairEl = document.getElementById("current-pair");
const statusEl = document.getElementById("status");
const historyEl = document.getElementById("history");

let remainingPairs = [];
let drawnPairs = [];

function buildPairs(totalPages) {
  const pairs = [];
  for (let page = 1; page <= totalPages; page += 2) {
    pairs.push([page, page + 1]);
  }
  return pairs;
}

function shuffle(array) {
  for (let i = array.length - 1; i > 0; i -= 1) {
    const j = Math.floor(Math.random() * (i + 1));
    [array[i], array[j]] = [array[j], array[i]];
  }
  return array;
}

function renderStatus() {
  if (remainingPairs.length === 0 && drawnPairs.length > 0) {
    statusEl.textContent = `完了: ${drawnPairs.length} / ${drawnPairs.length} 組を抽選しました`;
    return;
  }

  const total = remainingPairs.length + drawnPairs.length;
  statusEl.textContent = `進捗: ${drawnPairs.length} / ${total} 組（残り ${remainingPairs.length} 組）`;
}

function renderHistory() {
  historyEl.innerHTML = "";
  drawnPairs.forEach((pair, index) => {
    const li = document.createElement("li");
    li.textContent = `${index + 1}回目: ${pair[0]} - ${pair[1]} ページ`;
    historyEl.appendChild(li);
  });
}

function setMessage(text, isError = false) {
  messageEl.textContent = text;
  messageEl.style.color = isError ? "#c62828" : "#1c7a2d";
}

function resetState() {
  remainingPairs = [];
  drawnPairs = [];
  currentPairEl.textContent = "-";
  statusEl.textContent = "未開始";
  historyEl.innerHTML = "";
  drawBtn.disabled = true;
  resetBtn.disabled = true;
}

setupBtn.addEventListener("click", () => {
  const totalPages = Number(totalPagesInput.value);

  if (!Number.isInteger(totalPages) || totalPages < 2 || totalPages % 2 !== 0) {
    setMessage("総ページ数は2以上の偶数を入力してください。", true);
    return;
  }

  remainingPairs = shuffle(buildPairs(totalPages));
  drawnPairs = [];
  currentPairEl.textContent = "-";
  renderHistory();
  renderStatus();

  drawBtn.disabled = false;
  resetBtn.disabled = false;
  setMessage(`抽選を準備しました（全 ${remainingPairs.length} 組）。`);
});

drawBtn.addEventListener("click", () => {
  if (remainingPairs.length === 0) {
    setMessage("すべての組を引き終えています。", true);
    drawBtn.disabled = true;
    return;
  }

  const picked = remainingPairs.pop();
  drawnPairs.push(picked);

